-- Question #1 (Numerical Ability - Time Speed and Distance)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0001', 'A train passes a station platform in 36 seconds and a man standing on the platform in 20 seconds. If the speed of the train is 54 km/hr, what is the length of the platform?', NULL, '[{"id": "A", "text": "120 m"}, {"id": "B", "text": "240 m"}, {"id": "C", "text": "300 m"}, {"id": "D", "text": "360 m"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Convert the speed of the train from km/hr to m/s.
Speed = 54 km/hr = 54 * (5/18) m/s = 3 * 5 = 15 m/s.

Step 2: Find the length of the train.
When a train passes a standing man, the distance covered is equal to the length of the train.
Length of Train = Speed * Time to pass the man
Length of Train = 15 m/s * 20 seconds = 300 meters.

Step 3: Find the length of the platform.
When a train passes a platform, the total distance covered is the sum of the train length and the platform length.
Let the platform length be L.
Total Distance = 300 + L.
Time to pass the platform = 36 seconds.
Speed = Total Distance / Time
15 = (300 + L) / 36
300 + L = 15 * 36
300 + L = 540
L = 540 - 300 = 240 meters.

Therefore, the length of the platform is 240 m.', NULL, 'Time Speed and Distance', 'Trains', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Forgetting to convert speed from km/hr to m/s, or using the train length directly as the answer.', ARRAY['trains', 'speed-conversion', 'arithmetic']::text[], 'Inspired'::nqt_source_type, 2024, 4, TRUE
);

-- Question #2 (Numerical Ability - Number System)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
