    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0002', 'Find the least number which when divided by 12, 16, 18, and 30 leaves a remainder of 4 in each case, but when divided by 7 leaves no remainder.', NULL, '[{"id": "A", "text": "364"}, {"id": "B", "text": "724"}, {"id": "C", "text": "1084"}, {"id": "D", "text": "2884"}]'::jsonb, 'D', 
    'Step-by-step Solution:

Step 1: Find the LCM of the divisors 12, 16, 18, and 30.
- Prime factorization of 12 = 2^2 * 3
- Prime factorization of 16 = 2^4
- Prime factorization of 18 = 2 * 3^2
- Prime factorization of 30 = 2 * 3 * 5
LCM = 2^4 * 3^2 * 5 = 16 * 9 * 5 = 720.

Step 2: Express the required number in terms of the LCM.
Any number leaving a remainder of 4 when divided by 12, 16, 18, and 30 is of the form: 
Number = 720k + 4 (where k is a positive integer).

Step 3: Find the value of k such that (720k + 4) is exactly divisible by 7.
We can write 720k + 4 as:
(7 * 102k) + 6k + 4 = 714k + 6k + 4.
Since 714k is divisible by 7, we only need to find a value of k for which (6k + 4) is divisible by 7:
- For k = 1: 6(1) + 4 = 10 (Not divisible by 7)
- For k = 2: 6(2) + 4 = 16 (Not divisible by 7)
- For k = 3: 6(3) + 4 = 22 (Not divisible by 7)
- For k = 4: 6(4) + 4 = 28 (Divisible by 7: 28 / 7 = 4)

Step 4: Substitute k = 4 into the original formula.
Number = 720 * 4 + 4 = 2880 + 4 = 2884.

Therefore, the least number is 2884.', NULL, 'Number System', 'HCF and LCM', 
    'Hard'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 90, 
    'Calculating LCM incorrectly or picking 364 (which works for 12, 18, 30 but not 16).', ARRAY['lcm-hcf', 'divisibility', 'number-theory']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

-- Question #3 (Numerical Ability - Time and Work)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0003', 'Pipe A can fill a tank in 12 hours and Pipe B can fill it in 15 hours. If both pipes are opened together and Pipe A is closed after 4 hours, how much additional time (in hours) will Pipe B take to fill the remaining part of the tank?', NULL, '[{"id": "A", "text": "5 hours"}, {"id": "B", "text": "6 hours"}, {"id": "C", "text": "8 hours"}, {"id": "D", "text": "9 hours"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Calculate the total capacity of the tank and efficiencies.
Let the capacity of the tank be the LCM of 12 and 15 = 60 units.
- Efficiency of Pipe A = 60 / 12 = 5 units/hour
- Efficiency of Pipe B = 60 / 15 = 4 units/hour

Step 2: Find the work done while both pipes are open.
Combined efficiency of A and B = 5 + 4 = 9 units/hour.
Work done in 4 hours = 9 units/hour * 4 hours = 36 units.

Step 3: Calculate the remaining work.
Remaining capacity = 60 - 36 = 24 units.

Step 4: Find the additional time taken by Pipe B to fill the remaining capacity.
Additional time = Remaining capacity / Efficiency of Pipe B
Additional time = 24 units / 4 units/hour = 6 hours.

Therefore, Pipe B will take 6 additional hours to fill the tank.', NULL, 'Time and Work', 'Pipes and Cisterns', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 60, 
    'Calculating total time instead of additional time (total time is 4 + 6 = 10 hours).', ARRAY['time-and-work', 'pipes-cisterns', 'arithmetic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #4 (Numerical Ability - Simple and Compound Interest)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0004', 'The difference between simple interest and compound interest (compounded annually) on a certain sum of money for 2 years at 8% per annum is $48. Find the principal sum.', NULL, '[{"id": "A", "text": "$7,500"}, {"id": "B", "text": "$6,000"}, {"id": "C", "text": "$8,000"}, {"id": "D", "text": "$7,200"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Identify the standard formula for the difference between CI and SI for 2 years.
Difference (D) = P * (R / 100)^2
where P is the principal sum and R is the rate of interest.

Step 2: Substitute the given values into the formula.
Here, D = $48, R = 8%.
48 = P * (8 / 100)^2

Step 3: Solve for P.
48 = P * (64 / 10,000)
P = (48 * 10,000) / 64
P = 480,000 / 64
P = 7,500.

Therefore, the principal sum is $7,500.', NULL, 'Simple and Compound Interest', 'Interest Difference', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 70, 
    'Using the 3-year formula instead of the 2-year formula or mixing up the terms in the formula.', ARRAY['interest', 'compound-interest', 'arithmetic']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

