) VALUES (
    'NQT-0006', 'An article is listed at $1,500. Two successive discounts of 20% and 10% are offered. What is the final selling price of the article?', NULL, '[{"id": "A", "text": "$1,050"}, {"id": "B", "text": "$1,080"}, {"id": "C", "text": "$1,100"}, {"id": "D", "text": "$1,200"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Method 1: Step-by-step calculation
Step 1: Calculate the price after the first discount of 20%.
Discount 1 = 20% of 1500 = 1500 * 0.20 = $300.
Price after Discount 1 = 1500 - 300 = $1,200.

Step 2: Calculate the price after the second discount of 10% on the reduced price.
Discount 2 = 10% of 1200 = 1200 * 0.10 = $120.
Final Selling Price = 1200 - 120 = $1,080.

Method 2: Single equivalent discount
Step 1: Find the combined single equivalent discount percentage using the formula:
Equivalent Discount = d1 + d2 - (d1 * d2 / 100)
Equivalent Discount = 20 + 10 - (20 * 10 / 100) = 30 - 2 = 28%.

Step 2: Apply the equivalent discount to the original price.
Final Selling Price = 1500 * (100% - 28%) = 1500 * 0.72 = $1,080.

Therefore, the final selling price is $1,080.', NULL, 'Profit and Loss', 'Successive Discounts', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Adding the discounts directly (20% + 10% = 30% discount on $1500 = $1050).', ARRAY['discounts', 'profit-loss', 'arithmetic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #7 (Numerical Ability - Time and Work)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0007', 'A and B can complete a work in 10 days and 15 days respectively. They work on alternate days starting with A. In how many days will the work be completed?', NULL, '[{"id": "A", "text": "11 days"}, {"id": "B", "text": "12 days"}, {"id": "C", "text": "12.5 days"}, {"id": "D", "text": "13 days"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Determine the total work and individual efficiencies.
Let the total work be the LCM of 10 and 15 = 30 units.
- Efficiency of A = 30 / 10 = 3 units/day
- Efficiency of B = 30 / 15 = 2 units/day

Step 2: Calculate the work done in one 2-day cycle (alternate working).
- Day 1 (A works): 3 units
- Day 2 (B works): 2 units
Total work done in 1 cycle (2 days) = 3 + 2 = 5 units.

Step 3: Divide the total work by the work done per cycle.
Number of 2-day cycles required = Total work / Work per cycle = 30 / 5 = 6 cycles.

Step 4: Find the total number of days.
Total days = 6 cycles * 2 days/cycle = 12 days.

Therefore, the work will be completed in 12 days.', NULL, 'Time and Work', 'Alternate Days', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 70, 
    'Incorrect cycle division, or assuming they work together (which would take 6 days total).', ARRAY['time-and-work', 'alternate-days', 'arithmetic']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #8 (Numerical Ability - Percentages)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0008', 'If A''s income is 25% more than B''s income, by what percentage is B''s income less than A''s income?', NULL, '[{"id": "A", "text": "20%"}, {"id": "B", "text": "25%"}, {"id": "C", "text": "16.67%"}, {"id": "D", "text": "15%"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Assume a base value for B''s income.
Let B''s income be $100.

Step 2: Determine A''s income.
Since A''s income is 25% more than B''s:
A''s income = 100 + 25% of 100 = $125.

Step 3: Calculate the difference in their incomes.
Difference = A''s income - B''s income = 125 - 100 = $25.

Step 4: Calculate by what percentage B''s income is less than A''s income.
We compare the difference relative to A''s income:
Percentage Less = (Difference / A''s income) * 100
Percentage Less = (25 / 125) * 100 = (1 / 5) * 100 = 20%.

Therefore, B''s income is 20% less than A''s income.', NULL, 'Percentages', 'Income Comparison', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 40, 
    'Answering 25% directly because A is 25% more than B.', ARRAY['percentages', 'arithmetic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #9 (Numerical Ability - Ratio and Proportion)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0009', 'A, B, and C invest in a partnership in the ratio of 3 : 5 : 7. After 6 months, C withdraws half of his capital. If the total profit at the end of the year is $106,000, what is C''s share of the profit?', NULL, '[{"id": "A", "text": "$36,000"}, {"id": "B", "text": "$42,000"}, {"id": "C", "text": "$40,000"}, {"id": "D", "text": "$44,000"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Set up the initial investment ratios.
Let the investments of A, B, and C be 3x, 5x, and 7x.

Step 2: Calculate the weighted investment of each partner (Investment * Time in months).
- A stays in the partnership for the full 12 months with initial capital:
  A''s product = 3x * 12 = 36x
- B stays in the partnership for the full 12 months with initial capital:
  B''s product = 5x * 12 = 60x
- C stays for 6 months with 7x capital, then withdraws half (leaving 3.5x capital) for the remaining 6 months:
  C''s product = (7x * 6) + (3.5x * 6) = 42x + 21x = 63x

Step 3: Find the ratio of profit distribution.
Profit sharing ratio A : B : C = 36x : 60x : 63x = 36 : 60 : 63.
Dividing by the common factor 3, we get:
Profit sharing ratio A : B : C = 12 : 20 : 21.

Step 4: Determine C''s share of the total profit.
Total units of profit = 12 + 20 + 21 = 53 units.
Total profit = $106,000.
Value of 1 unit = 106,000 / 53 = $2,000.
C''s share (21 units) = 21 * 2,000 = $42,000.

Therefore, C''s share of the profit is $42,000.', NULL, 'Ratio and Proportion', 'Partnership', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 80, 
    'Ignoring the time factor and dividing profit directly in the ratio 3:5:7, or forgetting that C only withdrew half his capital (meaning half remained).', ARRAY['ratio-proportion', 'partnership', 'arithmetic']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

