    'NQT-0010', 'The average weight of 8 persons increases by 2.5 kg when a new person comes in place of one of them weighing 65 kg. What is the weight of the new person?', NULL, '[{"id": "A", "text": "75 kg"}, {"id": "B", "text": "80 kg"}, {"id": "C", "text": "85 kg"}, {"id": "D", "text": "90 kg"}]'::jsonb, 'C', 
