-- Question #11 (Numerical Ability - Number System)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0011', 'What is the unit digit of the expression (37)^123 * (43)^56 * (57)^89?', NULL, '[{"id": "A", "text": "1"}, {"id": "B", "text": "3"}, {"id": "C", "text": "7"}, {"id": "D", "text": "9"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Simplify the base of each term to its unit digit.
We only need to find the unit digits of: 7^123 * 3^56 * 7^89.

Step 2: Understand the cyclicity of the unit digits of 7 and 3.
Both 7 and 3 have a cyclicity of 4.
- Unit digits of powers of 7: 7^1=7, 7^2=9, 7^3=3, 7^4=1 (repeats 7, 9, 3, 1)
- Unit digits of powers of 3: 3^1=3, 3^2=9, 3^3=7, 3^4=1 (repeats 3, 9, 7, 1)

Step 3: Find the unit digit of each term by dividing the exponents by 4.
- For 7^123: 123 % 4 = 3. Thus, the unit digit is the same as 7^3 = 343, which is 3.
- For 3^56: 56 % 4 = 0 (perfectly divisible, which maps to index 4). Thus, the unit digit is the same as 3^4 = 81, which is 1.
- For 7^89: 89 % 4 = 1. Thus, the unit digit is the same as 7^1 = 7.

Step 4: Multiply the unit digits together to get the final unit digit.
Product of unit digits = 3 * 1 * 7 = 21.
The unit digit of 21 is 1.

Therefore, the unit digit of the entire expression is 1.', NULL, 'Number System', 'Unit Digit', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Forgetting the cyclicity rules, or incorrectly calculating exponents (e.g. thinking 56%4 = 4 instead of remainder 0 which maps to power 4).', ARRAY['number-system', 'unit-digit', 'cyclicity']::text[], 'Inspired'::nqt_source_type, 2024, 4, TRUE
);

-- Question #12 (Numerical Ability - Surds and Indices)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0012', 'If 3^(x - y) = 27 and 3^(x + y) = 243, find the value of x * y.', NULL, '[{"id": "A", "text": "4"}, {"id": "B", "text": "5"}, {"id": "C", "text": "6"}, {"id": "D", "text": "8"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Convert the equations to have the same base (3).
- 3^(x - y) = 27 => 3^(x - y) = 3^3
- 3^(x + y) = 243 => 3^(x + y) = 3^5

Step 2: Equate the exponents to form a system of linear equations.
1) x - y = 3
2) x + y = 5

Step 3: Solve the system of equations.
- Add Equation 1 and Equation 2:
  (x - y) + (x + y) = 3 + 5
  2x = 8
  x = 4.
- Substitute x = 4 into Equation 2:
  4 + y = 5
  y = 1.

Step 4: Find the product x * y.
x * y = 4 * 1 = 4.

Therefore, the value of x * y is 4.', NULL, 'Surds and Indices', 'Equations with Powers', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Solving for x and y but forgetting to multiply them to get x * y.', ARRAY['indices', 'algebra', 'equations']::text[], 'Original'::nqt_source_type, 2023, 3, TRUE
);

-- Question #13 (Numerical Ability - Permutation and Combination)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0013', 'In how many different ways can the letters of the word ''CORPORATION'' be arranged so that the vowels always come together?', NULL, '[{"id": "A", "text": "48,000"}, {"id": "B", "text": "50,400"}, {"id": "C", "text": "120,960"}, {"id": "D", "text": "720"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Identify the vowels and consonants in the word ''CORPORATION''.
Total letters = 11.
- Vowels: O, O, A, I, O (Total = 5 vowels, where ''O'' is repeated 3 times)
- Consonants: C, R, P, R, T, N (Total = 6 consonants, where ''R'' is repeated 2 times)

Step 2: Group the vowels together.
Since the vowels must always come together, we treat the group of 5 vowels (OOAIO) as a single unit or letter.
Now, we have: 6 consonants + 1 vowel group = 7 units to arrange.

Step 3: Calculate the arrangements of the 7 units.
In the 7 units, the consonant ''R'' is repeated 2 times.
Number of arrangements = 7! / 2!
Number of arrangements = 5040 / 2 = 2520.

Step 4: Calculate the arrangements of the vowels within their group.
Within the vowel group, there are 5 letters: O, O, A, I, O (where ''O'' is repeated 3 times).
Number of arrangements = 5! / 3!
Number of arrangements = 120 / 6 = 20.

Step 5: Multiply the two results to get the total arrangements.
Total ways = 2520 * 20 = 50,400.

Therefore, the letters can be arranged in 50,400 ways.', NULL, 'Permutation and Combination', 'Word Arrangements', 
    'Hard'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 90, 
    'Forgetting to divide by the repeating letters (R twice, O three times) or miscounting the number of consonants and vowels.', ARRAY['permutations', 'combinatorics', 'vowels-together']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

-- Question #14 (Numerical Ability - Probability)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0014', 'A bag contains 4 white, 5 red, and 6 blue balls. Three balls are drawn at random from the bag. What is the probability that all of them are red?', NULL, '[{"id": "A", "text": "1/22"}, {"id": "B", "text": "2/91"}, {"id": "C", "text": "3/22"}, {"id": "D", "text": "2/77"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Calculate the total number of balls in the bag.
Total balls = 4 (white) + 5 (red) + 6 (blue) = 15 balls.

Step 2: Calculate the total number of ways to select any 3 balls out of 15.
This is a combination problem: 15C3.
Total outcomes = (15 * 14 * 13) / (3 * 2 * 1) = 5 * 7 * 13 = 455.

Step 3: Calculate the number of favorable ways to draw 3 red balls out of the 5 available red balls.
Favorable outcomes = 5C3 = 5C2 = (5 * 4) / (2 * 1) = 10.

Step 4: Compute the probability.
Probability = Favorable outcomes / Total outcomes
Probability = 10 / 455 = 2 / 91.

Therefore, the probability that all three drawn balls are red is 2/91.', NULL, 'Probability', 'Ball Selection', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 70, 
    'Calculating probability as (5/15) * (5/15) * (5/15) by assuming replacement, when the draw is done without replacement.', ARRAY['probability', 'combinations']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #15 (Numerical Ability - Mensuration)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0015', 'A metallic sphere of radius 6 cm is melted and recast into a wire of cylinder cross-section with radius 0.2 cm. Find the length of the wire (in meters).', NULL, '[{"id": "A", "text": "72 m"}, {"id": "B", "text": "144 m"}, {"id": "C", "text": "288 m"}, {"id": "D", "text": "18 m"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Understand that melting and recasting preserves the total volume of metal.
Volume of Sphere = Volume of Cylindrical Wire.

Step 2: Calculate the volume of the metallic sphere.
Volume of sphere = (4/3) * pi * R^3
Given R = 6 cm:
Volume = (4/3) * pi * 6 * 6 * 6 = 4 * pi * 2 * 36 = 288 * pi cm^3.

Step 3: Calculate the volume of the cylindrical wire.
Volume of cylinder = pi * r^2 * h
Given r = 0.2 cm, and let h be the length (height) of the wire:
Volume = pi * (0.2)^2 * h = 0.04 * pi * h cm^3.

Step 4: Equate the volumes and solve for h.
288 * pi = 0.04 * pi * h
288 = 0.04 * h
h = 288 / 0.04 = 28800 / 4 = 7200 cm.

Step 5: Convert the length from centimeters to meters.
h = 7200 cm = 7200 / 100 meters = 72 meters.

Therefore, the length of the wire is 72 meters.', NULL, 'Mensuration', 'Melting and Recasting', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 80, 
    'Not converting the final height/length from cm to meters, or squaring the cylinder radius incorrectly.', ARRAY['geometry', 'mensuration', 'volume']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

-- Question #16 (Numerical Ability - Mixtures and Alligations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0016', 'A mixture contains milk and water in the ratio of 4 : 3. If 5 liters of water is added to the mixture, the ratio becomes 4 : 5. Find the initial quantity of milk in the mixture (in liters).', NULL, '[{"id": "A", "text": "10 liters"}, {"id": "B", "text": "12 liters"}, {"id": "C", "text": "15 liters"}, {"id": "D", "text": "20 liters"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Set up equations based on ratios.
Let the initial quantity of milk be 4x and water be 3x.

Step 2: Adjust the mixture for the added water.
5 liters of water is added. The new quantity of water is (3x + 5) liters. The quantity of milk remains 4x.
The new ratio of milk to water is 4 : 5.

Step 3: Solve the equation.
4x / (3x + 5) = 4 / 5
Cross-multiplying:
5 * (4x) = 4 * (3x + 5)
20x = 12x + 20
20x - 12x = 20
8x = 20
x = 2.5.

Step 4: Find the initial quantity of milk.
Milk = 4x = 4 * 2.5 = 10 liters.

Therefore, the initial quantity of milk was 10 liters.', NULL, 'Mixtures and Alligations', 'Ratio Adjustments', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Finding total volume (7x = 17.5L) or water quantity (3x = 7.5L) instead of milk.', ARRAY['mixtures', 'ratios', 'arithmetic']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #17 (Numerical Ability - Number System)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0017', 'If the sum of two numbers is 55 and their HCF and LCM are 5 and 120 respectively, then the sum of the reciprocals of the numbers is:', NULL, '[{"id": "A", "text": "11/120"}, {"id": "B", "text": "120/11"}, {"id": "C", "text": "11/24"}, {"id": "D", "text": "55/120"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Define variables for the two numbers.
Let the two numbers be ''a'' and ''b''. We are given:
a + b = 55.

Step 2: Connect the product of the numbers to their HCF and LCM.
A fundamental mathematical property states that:
Product of two numbers = HCF * LCM
a * b = 5 * 120 = 600.

Step 3: Express the sum of the reciprocals algebraically.
Sum of reciprocals = 1/a + 1/b = (a + b) / (a * b)

Step 4: Substitute the values from Step 1 and Step 2.
Sum of reciprocals = 55 / 600
Simplifying by dividing numerator and denominator by 5:
Sum of reciprocals = 11 / 120.

Therefore, the sum of their reciprocals is 11/120.', NULL, 'Number System', 'Reciprocals and HCF/LCM', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 45, 
    'Trying to solve for the individual values of a and b first, which takes much longer, rather than using the reciprocal formula directly.', ARRAY['number-system', 'lcm-hcf']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #18 (Numerical Ability - Equations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0018', 'If the roots of the quadratic equation x^2 - px + q = 0 differ by 1, then which of the following is true?', NULL, '[{"id": "A", "text": "p^2 = 4q + 1"}, {"id": "B", "text": "p^2 = 4q - 1"}, {"id": "C", "text": "q^2 = 4p + 1"}, {"id": "D", "text": "q^2 = 4p - 1"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Relate roots to coefficients using Vieta''s formulas.
Let the roots of the equation x^2 - px + q = 0 be a and b.
- Sum of roots (a + b) = -(-p)/1 = p
- Product of roots (a * b) = q/1 = q

Step 2: Set up the given relation.
We are given that the roots differ by 1:
|a - b| = 1 => (a - b)^2 = 1.

Step 3: Connect (a - b)^2 with sum and product of roots.
We use the algebraic identity: (a - b)^2 = (a + b)^2 - 4ab.

Step 4: Substitute the expressions from Step 1 into the identity.
1 = p^2 - 4q
p^2 = 4q + 1.

Therefore, the relation p^2 = 4q + 1 is true.', NULL, 'Equations', 'Quadratic Equations', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 60, 
    'Mixing up the algebraic identity signs (e.g. thinking (a-b)^2 = (a+b)^2 + 4ab).', ARRAY['algebra', 'quadratic-equations']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

-- Question #19 (Numerical Ability - Progressions)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0019', 'Find the sum of all natural numbers between 100 and 300 which are exactly divisible by 7.', NULL, '[{"id": "A", "text": "5586"}, {"id": "B", "text": "5724"}, {"id": "C", "text": "5530"}, {"id": "D", "text": "5600"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Find the first and last terms divisible by 7 between 100 and 300.
- Divide 100 by 7: 100 / 7 = 14.28. The first term is 7 * 15 = 105.
- Divide 300 by 7: 300 / 7 = 42.85. The last term is 7 * 42 = 294.

Step 2: Identify the Arithmetic Progression (AP).
The numbers form an AP: 105, 112, 119, ..., 294.
Here:
- First term (a) = 105
- Common difference (d) = 7
- Last term (l) = 294

Step 3: Determine the number of terms (n).
We use the formula: l = a + (n - 1) * d
294 = 105 + (n - 1) * 7
294 - 105 = 7 * (n - 1)
189 = 7 * (n - 1)
n - 1 = 189 / 7 = 27
n = 28.

Step 4: Calculate the sum of the AP.
We use the formula: Sn = (n / 2) * (a + l)
S = (28 / 2) * (105 + 294)
S = 14 * 399 = 5,586.

Therefore, the sum of these numbers is 5,586.', NULL, 'Progressions', 'Arithmetic Progression', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Misidentifying the first or last term, or miscalculating the number of terms n (e.g., off-by-one errors).', ARRAY['progressions', 'ap', 'arithmetic', 'divisibility']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #20 (Numerical Ability - Number System)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0020', 'If a number 5432*7 is completely divisible by 9, then what digit should replace the asterisk (*)?', NULL, '[{"id": "A", "text": "0"}, {"id": "B", "text": "6"}, {"id": "C", "text": "9"}, {"id": "D", "text": "8"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: State the divisibility rule for 9.
A number is divisible by 9 if and only if the sum of its individual digits is a multiple of 9.

Step 2: Calculate the sum of the known digits.
Sum = 5 + 4 + 3 + 2 + 7 = 21.

Step 3: Formulate an expression with the missing digit (let it be x).
Sum of all digits = 21 + x.

Step 4: Find the value of x (where x is a single digit: 0, 1, ..., 9) such that (21 + x) is divisible by 9.
Multiples of 9 are 9, 18, 27, 36, ...
The next multiple of 9 immediately greater than or equal to 21 is 27.
21 + x = 27
x = 27 - 21 = 6.

Therefore, the missing digit is 6.', NULL, 'Number System', 'Divisibility Rules', 
    'Easy'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 30, 
    'Adding digits incorrectly or using divisibility rule of 3 or 11 by mistake.', ARRAY['divisibility', 'number-system']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #21 (Reasoning Ability - Coding Decoding)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0021', 'In a certain code language, ''ROBUST'' is written as ''QNATRS''. How is ''BORDER'' written in that language?', NULL, '[{"id": "A", "text": "ANQCQD"}, {"id": "B", "text": "AOQDDQ"}, {"id": "C", "text": "AQCQDD"}, {"id": "D", "text": "AMQDDQ"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Analyze the pattern in the example word.
Compare the letters of ''ROBUST'' with ''QNATRS'' side-by-side:
- R -> Q (-1 shift: Q is the letter before R)
- O -> N (-1 shift: N is the letter before O)
- B -> A (-1 shift: A is the letter before B)
- U -> T (-1 shift: T is the letter before U)
- S -> R (-1 shift: R is the letter before S)
- T -> S (-1 shift: S is the letter before T)
The pattern is that every letter in the word is shifted backward by 1 character (-1).

Step 2: Apply the same pattern to the target word ''BORDER''.
- B - 1 = A
- O - 1 = N
- R - 1 = Q
- D - 1 = C
- E - 1 = D
- R - 1 = Q
Putting it all together, BORDER is encoded as ANQCQD.

Step 3: Match with options.
ANQCQD corresponds to Option A.', NULL, 'Coding Decoding', 'Letter Shifts', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 45, 
    'Shifting forward instead of backward, which would yield ''CPSDFS''.', ARRAY['coding-decoding', 'logic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #22 (Reasoning Ability - Blood Relations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0022', 'Pointing to a photograph of a boy, Suresh said, ''He is the son of the only son of my mother.'' How is Suresh related to that boy?', NULL, '[{"id": "A", "text": "Brother"}, {"id": "B", "text": "Uncle"}, {"id": "C", "text": "Father"}, {"id": "D", "text": "Cousin"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Break down the description from the speaker''s perspective (''my mother'').
Suresh is speaking: ''my mother'' refers to Suresh''s mother.

Step 2: Analyze ''only son of my mother''.
The only son of Suresh''s mother must be Suresh himself (assuming Suresh is male, which is standard for Suresh, or Suresh is the speaker referring to their mother''s only son).

Step 3: Analyze ''He is the son of...''
Substituting ''Suresh'' back into the phrase:
He is the son of [Suresh].

Step 4: Relate Suresh back to the boy.
Since the boy is the son of Suresh, Suresh is the Father of the boy.

Therefore, Suresh is the father of the boy.', NULL, 'Blood Relations', 'Pointing to Photograph', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 40, 
    'Misinterpreting ''only son of Suresh''s mother'' as Suresh''s brother, leading to Uncle as the answer.', ARRAY['blood-relations', 'logic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #23 (Reasoning Ability - Blood Relations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0023', 'If ''A + B'' means A is the brother of B; ''A - B'' means A is the sister of B; and ''A * B'' means A is the father of B. Which of the following means that C is the son of M?', NULL, '[{"id": "A", "text": "M * C - N"}, {"id": "B", "text": "M * N - C"}, {"id": "C", "text": "M * C + N"}, {"id": "D", "text": "M * N + C"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Determine the requirements for ''C is the son of M''.
- M must be the parent (specifically father here, given the ''*'' operator) of C.
- C must be male (brother relation ''+'').

Step 2: Evaluate the option candidates.
- Let''s check Option A: M * C - N
  * M * C means M is the father of C.
  * C - N means C is the sister of N (establishing C as female).
  Therefore, C is the daughter of M. Incorrect.

- Let''s check Option B: M * N - C
  * M * N means M is the father of N.
  * N - C means N is the sister of C.
  This does not define C''s gender or direct relation as M''s son. Incorrect.

- Let''s check Option C: M * C + N
  * M * C means M is the father of C.
  * C + N means C is the brother of N (establishing C as male).
  Since M is the father of C and C is male, C is indeed the son of M. Correct.

Therefore, option C represents ''C is the son of M''.', NULL, 'Blood Relations', 'Coded Blood Relations', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Forgetting to verify the gender of C, leading to choosing Option A (where C is a female/daughter).', ARRAY['blood-relations', 'logic', 'coded-relations']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #24 (Reasoning Ability - Direction Sense)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0024', 'A man walks 5 km toward South and then turns to the right. After walking 3 km he turns to the left and walks 5 km. Now in which direction is he from the starting place?', NULL, '[{"id": "A", "text": "West"}, {"id": "B", "text": "South"}, {"id": "C", "text": "South-West"}, {"id": "D", "text": "North-East"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Map the starting position.
Let the starting point be origin (0, 0) with North as +y, South as -y, East as +x, and West as -x.

Step 2: Trace the first leg of the journey.
- Walks 5 km South.
- New coordinates = (0, -5).

Step 3: Trace the second leg.
- Facing South, the man turns to his right (which is West).
- Walks 3 km West.
- New coordinates = (-3, -5).

Step 4: Trace the third leg.
- Facing West, the man turns left (which is South).
- Walks 5 km South.
- Final coordinates = (-3, -10).

Step 5: Determine the final direction from the starting point.
The starting point is (0, 0) and the final point is (-3, -10).
- -3 on the x-axis indicates West.
- -10 on the y-axis indicates South.
Thus, the final position (-3, -10) is in the South-West quadrant relative to (0, 0).

Therefore, he is in the South-West direction from the starting point.', NULL, 'Direction Sense', 'Relative Direction', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Mixing up left/right turns when facing South. (A right turn when facing South points West; a left turn when facing West points South).', ARRAY['directions', 'spatial-reasoning']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #25 (Reasoning Ability - Syllogism)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0025', 'Statements:
I. All pencils are pens.
II. Some pens are erasers.
Conclusions:
1. Some pencils are erasers.
2. Some pens are pencils.
Choose the correct option:', NULL, '[{"id": "A", "text": "Only conclusion 1 follows"}, {"id": "B", "text": "Only conclusion 2 follows"}, {"id": "C", "text": "Either 1 or 2 follows"}, {"id": "D", "text": "Neither 1 nor 2 follows"}]'::jsonb, 'B', 
    'Step-by-step Solution using Venn Diagrams:

Step 1: Represent Statement I (''All pencils are pens'') using circles.
Draw a circle for ''Pencils'' entirely inside a larger circle for ''Pens''.

Step 2: Represent Statement II (''Some pens are erasers'') on the same diagram.
Draw a circle for ''Erasers'' that overlaps with the ''Pens'' circle.
Note: There are two possible scenarios here:
- Case A: The ''Erasers'' circle overlaps ''Pens'' but does NOT touch the ''Pencils'' circle.
- Case B: The ''Erasers'' circle overlaps ''Pens'' and ALSO overlaps the ''Pencils'' circle.

Step 3: Evaluate Conclusion 1 (''Some pencils are erasers'').
For a conclusion to follow, it must be true in ALL possible scenarios.
In Case A, no pencil is an eraser. Since it is not true in all scenarios, Conclusion 1 does not follow.

Step 4: Evaluate Conclusion 2 (''Some pens are pencils'').
Since the ''Pencils'' circle is entirely inside the ''Pens'' circle, any region occupied by pencils is also occupied by pens. Therefore, some portion of pens is always pencils.
Thus, Conclusion 2 is always true and follows.

Therefore, only conclusion 2 follows.', NULL, 'Syllogism', 'Two Statements', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Assuming a connection between pencils and erasers simply because they both intersect with pens.', ARRAY['syllogism', 'logic', 'deductive-reasoning']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #26 (Reasoning Ability - Seating Arrangements)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0026', 'Six friends A, B, C, D, E, and F are sitting around a circular table facing the center. B is between F and D; A is two places left of E, and E is adjacent to F. Who is sitting opposite to A?', NULL, '[{"id": "A", "text": "B"}, {"id": "B", "text": "D"}, {"id": "C", "text": "E"}, {"id": "D", "text": "F"}]'::jsonb, 'D', 
    'Step-by-step Solution:

Step 1: Set up the circular positions.
Let 6 seats around the circular table be numbered 1 to 6 in clockwise order. Since they face the center, ''left'' refers to clockwise movement, and ''right'' refers to counter-clockwise.

Step 2: Place E and A based on the rules.
- Place E at Position 1.
- Rule: ''A is two places left of E''. Going clockwise from E: Position 2 is 1st left, Position 3 is 2nd left. Place A at Position 3.

Step 3: Place F based on E''s adjacency.
- Rule: ''E is adjacent to F''. E is at 1, so F must be at either Position 2 or Position 6.
- Scenario A: If F is at Position 2. Then B (who is between F and D) would need to be at Position 3 (which is already occupied by A). This is a conflict.
- Scenario B: Thus, F must be at Position 6.

Step 4: Place B and D.
- Rule: ''B is between F and D''. With F at 6, B must be at Position 5, and D must be at Position 4 (leaving B between F at 6 and D at 4).

Step 5: Place the remaining person.
- This leaves C to occupy Position 2.

Final arrangement (Positions 1 to 6): E(1), C(2), A(3), D(4), B(5), F(6).

Step 6: Determine who sits opposite to A.
In a 6-person circular table, the person opposite position x is position x + 3.
Opposite A (Position 3) is Position 6 (3 + 3), which is occupied by F.

Therefore, F is sitting opposite to A.', NULL, 'Seating Arrangements', 'Circular Arrangement', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 85, 
    'Mixing up clockwise/counter-clockwise directions for left/right turns when facing the center of a circle.', ARRAY['circular-seating', 'logical-deduction']::text[], 'Inspired'::nqt_source_type, 2024, 4, TRUE
);

-- Question #27 (Reasoning Ability - Seating Arrangements)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0027', 'Five people P, Q, R, S, and T are standing in a queue facing North. R is standing between P and T. Q is standing immediately to the left of T. S is standing at the extreme right end. Who is standing in the middle of the queue?', NULL, '[{"id": "A", "text": "P"}, {"id": "B", "text": "Q"}, {"id": "C", "text": "R"}, {"id": "D", "text": "T"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Set up the queue slots.
Let the 5 queue slots from left to right be 1, 2, 3, 4, 5 (facing North means left is left, right is right).

Step 2: Place S based on the rules.
- Rule: ''S is standing at the extreme right end''. Place S at slot 5.
Queue: [_, _, _, _, S]

Step 3: Analyze the group Q, T, R, P.
- Rule: ''Q is standing immediately to the left of T'' -> We have a block: [Q, T].
- Rule: ''R is standing between P and T''. This means the order must be either P-R-T or T-R-P.

Step 4: Check combinations.
- If order is P-R-T:
  Since Q is immediately left of T, we would have: P - R - [Q - T]. But R must be adjacent to both P and T, which is violated if Q is inserted. So this does not work.
- If order is T-R-P:
  Since Q is immediately left of T, we get the combined sequence: Q - T - R - P.

Step 5: Fit the sequence into the queue.
Since slot 5 is occupied by S, the 4-person sequence [Q, T, R, P] must occupy slots 1 to 4.
Queue: [Q(1), T(2), R(3), P(4), S(5)]

Step 6: Identify the middle slot.
The middle slot in a 5-person queue is slot 3, which is occupied by R.

Therefore, R is standing in the middle of the queue.', NULL, 'Seating Arrangements', 'Linear Arrangement', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Placing Q and T incorrectly, or misidentifying who is in the middle.', ARRAY['linear-seating', 'queues']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #28 (Reasoning Ability - Data Sufficiency)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0028', 'Each of the questions below consists of a question and two statements numbered I and II. Decide whether the data provided in the statements are sufficient to answer the question.
Question: What is the age of Rohan?
Statements:
I. Rohan is twice as old as his sister Sophia, who was born in 2012.
II. Rohan''s age is 5 years less than his brother Sahil''s age, and Sahil is 19 years old.
Choose the correct option:', NULL, '[{"id": "A", "text": "Statement I alone is sufficient, but Statement II alone is not sufficient"}, {"id": "B", "text": "Statement II alone is sufficient, but Statement I alone is not sufficient"}, {"id": "C", "text": "Either Statement I alone or Statement II alone is sufficient"}, {"id": "D", "text": "Both Statements I and II together are not sufficient"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Define what is required to answer the question.
To determine the age of Rohan, we need information that results in a single, concrete numerical value for his age.

Step 2: Analyze Statement I alone.
Statement I: ''Rohan is twice as old as his sister Sophia, who was born in 2012.''
- Sophia was born in 2012.
- Sophia''s age depends entirely on the current year. Since the current year is not specified in the question, Sophia''s age is unknown.
- Consequently, Rohan''s age cannot be calculated as a fixed number.
- Statement I alone is NOT sufficient.

Step 3: Analyze Statement II alone.
Statement II: ''Rohan''s age is 5 years less than his brother Sahil''s age, and Sahil is 19 years old.''
- Sahil''s age = 19 years.
- Rohan''s age = Sahil''s age - 5 = 19 - 5 = 14 years.
- This gives a unique, definitive numerical answer.
- Statement II alone is SUFFICIENT.

Therefore, Statement II alone is sufficient, but Statement I alone is not sufficient.', NULL, 'Data Sufficiency', 'Age Calculations', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 80, 
    'Assuming the current year is known and concluding that Statement I is also sufficient.', ARRAY['data-sufficiency', 'ages']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

-- Question #29 (Reasoning Ability - Clocks and Calendars)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0029', 'What is the angle (in degrees) between the hour hand and the minute hand of a clock at 8:30?', NULL, '[{"id": "A", "text": "60°"}, {"id": "B", "text": "75°"}, {"id": "C", "text": "85°"}, {"id": "D", "text": "90°"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Method 1: Formula
Step 1: State the clock angle formula.
Angle = |30H - 5.5M|
where H is hours and M is minutes.

Step 2: Substitute the values for 8:30 (H = 8, M = 30).
Angle = |30 * 8 - 5.5 * 30|
Angle = |240 - 165|
Angle = 75°.

Method 2: Logical Calculation
Step 1: Calculate the position of the minute hand.
At 30 minutes, the minute hand points exactly at the 6 mark (180° from 12).

Step 2: Calculate the position of the hour hand.
At 8:30, the hour hand has moved halfway between 8 and 9.
- Each hour mark represents 30° (360° / 12).
- Position of hour hand at 8 o''clock = 8 * 30° = 240°.
- In 30 minutes, the hour hand moves = 30 minutes * 0.5°/minute = 15°.
- Total position of hour hand = 240° + 15° = 255°.

Step 3: Calculate the difference between the positions.
Angle = 255° - 180° = 75°.

Therefore, the angle is 75°.', NULL, 'Clocks and Calendars', 'Angle Between Hands', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 45, 
    'Assuming the hour hand is exactly at 8 (which would make the angle 60°), forgetting that the hour hand moves as the minutes pass.', ARRAY['clocks', 'angles', 'logic']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #30 (Reasoning Ability - Clocks and Calendars)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0030', 'If January 1, 2016, was a Friday, what day of the week was January 1, 2017?', NULL, '[{"id": "A", "text": "Saturday"}, {"id": "B", "text": "Sunday"}, {"id": "C", "text": "Monday"}, {"id": "D", "text": "Tuesday"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Check if the year 2016 is a leap year.
A year is a leap year if it is divisible by 4.
2016 / 4 = 504 (perfectly divisible). Thus, 2016 is a leap year.

Step 2: Determine the number of days in 2016.
Since 2016 is a leap year, it has 366 days (including February 29).

Step 3: Calculate the number of odd days in the year.
Number of weeks = 366 / 7 = 52 weeks and 2 remaining days.
These 2 remaining days are the ''odd days''.

Step 4: Shift the day of the week by the number of odd days.
When we move from January 1 of one year to January 1 of the next year, the day of the week shifts by the number of odd days in the intervening year.
Since 2016 has 2 odd days:
January 1, 2017 = Friday + 2 days = Sunday.

Therefore, January 1, 2017 was a Sunday.', NULL, 'Clocks and Calendars', 'Calendar Odd Days', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Forgetting that 2016 is a leap year and only adding 1 odd day, resulting in Saturday.', ARRAY['calendars', 'leap-year', 'logic']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #31 (Reasoning Ability - Series Completion)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0031', 'Identify the missing number in the following series: 4, 9, 20, 43, 90, ?', NULL, '[{"id": "A", "text": "180"}, {"id": "B", "text": "185"}, {"id": "C", "text": "183"}, {"id": "D", "text": "187"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Check the differences between consecutive terms to see if there is a pattern.
- 9 - 4 = 5
- 20 - 9 = 11
- 43 - 20 = 23
- 90 - 43 = 47
The differences are 5, 11, 23, 47. Notice that: 
  * 5 * 2 + 1 = 11
  * 11 * 2 + 1 = 23
  * 23 * 2 + 1 = 47
This is one way to solve it, but let''s check a more direct multiplication relationship.

Step 2: Analyze the relationship between a term (n) and the next term (n+1).
- 4 -> 9: 4 * 2 + 1 = 9
- 9 -> 20: 9 * 2 + 2 = 20
- 20 -> 43: 20 * 2 + 3 = 43
- 43 -> 90: 43 * 2 + 4 = 90
The pattern is: Next Term = (Current Term * 2) + k (where k increases by 1 each step: 1, 2, 3, 4...).

Step 3: Apply the pattern to find the missing term.
The multiplier is 2, and the next value of k is 5:
Missing Term = (90 * 2) + 5
Missing Term = 180 + 5 = 185.

Therefore, the missing number is 185.', NULL, 'Series Completion', 'Number Series', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 45, 
    'Assuming a simple difference pattern or multiplying by 2 and adding 1 consistently without incrementing.', ARRAY['number-series', 'pattern-recognition']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #32 (Reasoning Ability - Venn Diagrams)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0032', 'Which of the following Venn diagrams correctly represents the relationship between ''Doctors'', ''Engineers'', and ''Professionals''?', NULL, '[{"id": "A", "text": "Two disjoint circles inside a larger circle"}, {"id": "B", "text": "Three intersecting circles"}, {"id": "C", "text": "Three disjoint circles"}, {"id": "D", "text": "One circle inside another circle, which is inside a third circle"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Analyze the categories independently.
- ''Doctors'' are individuals who practice medicine.
- ''Engineers'' are individuals who design/build machines or structures.
There is no overlap between the actual professions; a person cannot concurrently hold a job that is both a practicing doctor and practicing engineer. Thus, the circles for ''Doctors'' and ''Engineers'' must be disjoint (separate).

Step 2: Relate these categories to ''Professionals''.
Both doctors and engineers are classified as ''Professionals''. Therefore, both separate circles must lie entirely inside the larger circle representing ''Professionals''.

Step 3: Match with the choices.
This structure corresponds to: Two disjoint circles inside a larger circle (Option A).', NULL, 'Venn Diagrams', 'Logical Relations', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 30, 
    'Thinking that a person cannot be both a doctor and a professional, or overlapping doctor and engineer circles.', ARRAY['venn-diagrams', 'logic']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #33 (Reasoning Ability - Critical Reasoning)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0033', 'Statement: ''Buy our product to get a 50% discount and a chance to win a holiday package,'' advertised Company X.
Assumptions:
I. People are attracted to discounts and free holiday packages.
II. The product sold by Company X is of very high quality.
Choose the correct option:', NULL, '[{"id": "A", "text": "Only assumption I is implicit"}, {"id": "B", "text": "Only assumption II is implicit"}, {"id": "C", "text": "Both assumptions I and II are implicit"}, {"id": "D", "text": "Neither assumption I nor II is implicit"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Define what an ''implicit assumption'' is.
An assumption is something taken for granted or assumed to be true when making a statement.

Step 2: Evaluate Assumption I (''People are attracted to discounts and free holiday packages'').
- Company X is using these offers in their advertisement to encourage sales.
- Why would they do this? They must assume that people find discounts and holiday packages appealing enough to buy the product.
- Therefore, Assumption I is implicit in the company''s decision to advertise this way.

Step 3: Evaluate Assumption II (''The product sold by Company X is of very high quality'').
- The advertisement focuses entirely on financial discounts and rewards.
- There is no mention of product features, reliability, or quality in the statement.
- One does not need to assume the product is of high quality to offer a discount on it.
- Therefore, Assumption II is not implicit.

Hence, only assumption I is implicit.', NULL, 'Critical Reasoning', 'Statement and Assumptions', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 60, 
    'Conflating business marketing intentions (attracting customers via offers) with the quality of the actual product.', ARRAY['critical-reasoning', 'assumptions']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

-- Question #34 (Reasoning Ability - Critical Reasoning)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0034', 'Statement: Regular exercise significantly reduces the risk of heart disease.
Conclusions:
I. People who do not exercise will definitely suffer from heart disease.
II. Active lifestyle is beneficial for cardiac health.
Choose the correct option:', NULL, '[{"id": "A", "text": "Only conclusion I follows"}, {"id": "B", "text": "Only conclusion II follows"}, {"id": "C", "text": "Both conclusions I and II follow"}, {"id": "D", "text": "Neither conclusion I nor II follows"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Analyze the scope of the premise statement.
The premise states: Regular exercise (cause) -> significantly reduces the risk of heart disease (effect).
Note: It reduces the ''risk''; it does not eliminate it entirely, nor is it the only risk factor.

Step 2: Evaluate Conclusion I (''People who do not exercise will definitely suffer from heart disease'').
- The statement does not establish that lack of exercise is a direct, absolute guarantee of heart disease.
- The word ''definitely'' is too extreme and makes the conclusion logically invalid based on a probabilistic premise (reducing risk).
- Therefore, Conclusion I does not follow.

Step 3: Evaluate Conclusion II (''Active lifestyle is beneficial for cardiac health'').
- Regular exercise corresponds to an active lifestyle.
- Reducing the risk of heart disease directly implies a benefit to cardiac health.
- Therefore, Conclusion II follows logically and directly from the statement.

Hence, only conclusion II follows.', NULL, 'Critical Reasoning', 'Statement and Conclusions', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 50, 
    'Selecting Conclusion I because of logical inversion (assuming that if exercise helps, no exercise must mean disease).', ARRAY['critical-reasoning', 'conclusions']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #35 (Reasoning Ability - Visual and Spatial Reasoning)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0035', 'Which number replaces the question mark in the following grid?
[ 5 ] [ 7 ] [ 74 ]
[ 3 ] [ 8 ] [ 73 ]
[ 6 ] [ 4 ] [ ? ]', NULL, '[{"id": "A", "text": "50"}, {"id": "B", "text": "52"}, {"id": "C", "text": "48"}, {"id": "D", "text": "45"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Check mathematical relations in Row 1.
- Inputs: 5 and 7. Target output: 74.
- Let''s check addition: 5 + 7 = 12 (No)
- Let''s check multiplication: 5 * 7 = 35 (No, but 35 * 2 = 70, which is close)
- Let''s check sum of squares:
  5^2 + 7^2 = 25 + 49 = 74. (This matches exactly!)

Step 2: Test the same pattern on Row 2.
- Inputs: 3 and 8. Target output: 73.
- Sum of squares:
  3^2 + 8^2 = 9 + 64 = 73. (The pattern is confirmed!)

Step 3: Apply the pattern to Row 3 to find the missing value.
- Inputs: 6 and 4.
- Sum of squares:
  6^2 + 4^2 = 36 + 16 = 52.

Therefore, the missing number is 52.', NULL, 'Visual and Spatial Reasoning', 'Grid Patterns', 
    'Medium'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 60, 
    'Trying to find vertical relationships or arithmetic progressions instead of checking squares of row values.', ARRAY['puzzles', 'number-grid', 'logic']::text[], 'Inspired'::nqt_source_type, 2023, 3, TRUE
);

-- Question #36 (Verbal Ability - Sentence Completion)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0036', 'Select the word that best fits the meaning of the sentence:
The manager decided to ______ the meeting until next Tuesday because of the heavy rain forecast.', NULL, '[{"id": "A", "text": "call off"}, {"id": "B", "text": "put off"}, {"id": "C", "text": "hold up"}, {"id": "D", "text": "bring about"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Understand the context of the sentence.
The manager is changing the date of the meeting (''until next Tuesday'') due to a weather forecast. This means the meeting is being rescheduled or postponed.

Step 2: Analyze the phrasal verb choices.
- ''Put off'' means to postpone or delay to a later time. This fits perfectly.
- ''Call off'' means to cancel entirely. Since a new date (next Tuesday) is specified, the meeting is not canceled. Incorrect.
- ''Hold up'' means to delay or block progress. Incorrect.
- ''Bring about'' means to cause to happen. Incorrect.

Therefore, ''put off'' is the correct choice.', NULL, 'Sentence Completion', 'Phrasal Verbs', 
    'Easy'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 25, 
    'Confusing ''put off'' (postpone) with ''call off'' (cancel).', ARRAY['phrasal-verbs', 'grammar', 'vocabulary']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #37 (Verbal Ability - Sentence Completion)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0037', 'Select the word that best fits the meaning of the sentence:
Despite the team''s best efforts, the project was deemed a failure due to the ______ resources allocated to it.', NULL, '[{"id": "A", "text": "abundant"}, {"id": "B", "text": "superfluous"}, {"id": "C", "text": "meager"}, {"id": "D", "text": "redundant"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Understand the sentence logic.
- The word ''Despite'' indicates a contrast. Even though the team made their best efforts, the project failed.
- The cause of failure was the nature of the resources allocated to it. Therefore, the blank must be filled with a word that implies insufficient or inadequate resources.

Step 2: Evaluate the vocabulary choices.
- ''Abundant'' means plentiful or in large quantities. Incorrect (would not cause failure).
- ''Superfluous'' means excessive or unnecessary. Incorrect.
- ''Meager'' means lacking in quantity or quality (inadequate). This logically explains the failure. Correct.
- ''Redundant'' means no longer needed or duplicate. Incorrect.

Therefore, ''meager'' is the correct choice.', NULL, 'Sentence Completion', 'Vocabulary Context', 
    'Easy'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 25, 
    'Misunderstanding the word ''meager'' or selecting ''superfluous'' (which means excess).', ARRAY['vocabulary', 'contextual-vocab']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #38 (Verbal Ability - Spotting Errors)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0038', 'Identify the part of the sentence that contains an error:
Neither the teacher (A) / nor the students (B) / was present in (C) / the classroom yesterday (D).', NULL, '[{"id": "A", "text": "Neither the teacher"}, {"id": "B", "text": "nor the students"}, {"id": "C", "text": "was present in"}, {"id": "D", "text": "the classroom yesterday"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Identify the grammatical structure.
The sentence uses the correlative conjunction pair ''Neither... nor''.

Step 2: Recall the subject-verb agreement rule for ''Neither... nor''.
When two subjects are joined by ''neither... nor'', the verb agrees in number with the subject that is closer to it (proximity rule).
- Subject 1: ''the teacher'' (singular)
- Subject 2: ''the students'' (plural)

Step 3: Check the verb proximity.
The verb is ''was''. The subject closer to the verb is ''the students'' (plural).

Step 4: Identify the error.
A plural subject (''students'') requires a plural verb (''were''). Thus, ''was'' should be replaced with ''were''.
This error is in part C.

Therefore, part C is the correct option.', NULL, 'Spotting Errors', 'Subject Verb Agreement', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 35, 
    'Matching the verb with the first subject (''the teacher'') instead of the closer one (''the students'').', ARRAY['subject-verb-agreement', 'grammar', 'spotting-errors']::text[], 'Inspired'::nqt_source_type, 2024, 5, TRUE
);

-- Question #39 (Verbal Ability - Spotting Errors)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0039', 'Identify the part of the sentence that contains an error:
The flock of sheep (A) / were grazing in the valley (B) / when the wolf attacked (C) / without warning (D).', NULL, '[{"id": "A", "text": "The flock of sheep"}, {"id": "B", "text": "were grazing in the valley"}, {"id": "C", "text": "when the wolf attacked"}, {"id": "D", "text": "without warning"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Identify the subject of the sentence.
The subject is ''The flock of sheep''.

Step 2: Analyze the collective noun ''flock''.
''Flock'' is a collective noun. When a collective noun acts as a single cohesive unit, it takes a singular verb.
Here, the flock is behaving as a single unit grazing together.

Step 3: Analyze the verb.
The verb is ''were'' (plural).

Step 4: Identify the correction.
Since ''flock'' is singular, it requires the singular verb ''was''. The plural ''were'' is incorrect.
This error is in part B.

Therefore, part B is the correct option.', NULL, 'Spotting Errors', 'Collective Nouns', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 35, 
    'Looking at ''sheep'' and thinking the plural verb ''were'' is correct, ignoring the collective noun head ''flock''.', ARRAY['nouns', 'grammar', 'spotting-errors']::text[], 'Original'::nqt_source_type, 2024, 4, TRUE
);

-- Question #40 (Verbal Ability - Passage Recall)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0040', 'Rearrange the following sentences to form a coherent paragraph:
P. This research is crucial because global warming is accelerating rapidly.
Q. Scientists have been studying the melting of glaciers in the Antarctic.
R. The results indicate that sea levels could rise by several feet by the end of the century.
S. They have collected ice core samples to analyze past climate shifts.', NULL, '[{"id": "A", "text": "QSPR"}, {"id": "B", "text": "QSRP"}, {"id": "C", "text": "PQSR"}, {"id": "D", "text": "SPQR"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Find the introductory sentence.
- Sentence Q introduces the main subject: Scientists studying the melting of glaciers in the Antarctic. This is a standalone introduction. Thus, Q comes first.

Step 2: Look for pronoun linkages.
- Sentence S starts with ''They''. ''They'' is a pronoun referencing ''Scientists'' in sentence Q. S describes the immediate action taken by the scientists (collecting samples). Therefore, S must follow Q (Q -> S).

Step 3: Find the reference connection.
- Sentence P starts with ''This research''. This refers to the scientific work described in Q and S. P explains the significance of their research. This forms the chain (Q -> S -> P).

Step 4: Complete the logical transition.
- Sentence R concludes with the outcome of the research (''The results indicate...'').

Final order: Q-S-P-R.
This matches Option A.', NULL, 'Passage Recall', 'Sentence Rearrangement', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Placing P at the beginning or misconnecting the pronoun ''They'' to something other than ''Scientists''.', ARRAY['para-jumbles', 'reading-comprehension']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #41 (Verbal Ability - Passage Recall)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0041', 'Passage Recall - Read and Reconstruct:
"The Industrial Revolution, which began in Britain in the late 18th century, transformed rural societies into urban, industrial ones. The introduction of steam power and mechanized machinery led to unprecedented increases in production capacity, laying the groundwork for modern capitalism."
Reconstruct this passage in your own words, maintaining the core meaning and key facts.', NULL, NULL, 'The Industrial Revolution started in Britain during the late 1700s, shifting societies from rural farming to urban industrial centers. Inventions like steam engines and mechanized tools dramatically boosted manufacturing and production, setting the foundation for contemporary capitalism.', 
    'Step-by-step Solution Breakdown:

Step 1: Identify key historical facts that must be present in the reconstruction:
1. Origin/Location: Britain.
2. Timeline: Late 18th century (or late 1700s).
3. Social change: Rural to urban/industrial society.
4. Catalysts: Steam power and mechanized machinery.
5. Outcome: Increased production capacity and rise of modern capitalism.

Step 2: Paraphrase each fact without losing meaning:
- ''began in Britain in the late 18th century'' -> ''started in Britain during the late 1700s''
- ''transformed rural societies into urban, industrial ones'' -> ''shifting societies from rural farming to urban industrial centers''
- ''introduction of steam power and mechanized machinery'' -> ''inventions like steam engines and mechanized tools''
- ''led to unprecedented increases in production capacity, laying the groundwork for modern capitalism'' -> ''dramatically boosted manufacturing and production, setting the foundation for contemporary capitalism.''

Step 3: Combine these into coherent, original sentences as shown in the correct answer.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out the origin (Britain, late 18th century) or failing to mention steam power and mechanization.', ARRAY['passage-recall', 'writing-skills', 'reconstruction']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #42 (Verbal Ability - Email Writing)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0042', 'Email Writing - Situation Prompt:
Write an email to your project manager requesting a 3-day extension on your current software development project. Mention the reasons for the delay (e.g., api integration delays, server downtime) and provide a revised timeline. Write in complete sentences and maintain a professional tone. Length: 100-150 words.', NULL, NULL, 'Subject: Request for Project Deadline Extension

Dear [Manager''s Name],

I am writing to formally request a three-day extension on the deadline for our current software development project, originally scheduled for completion this Friday.

We encountered unexpected technical difficulties during the API integration phase, compounded by server downtime that halted development for a full day. Although these issues have now been resolved, they have set our timeline back.

With this extension, we will be able to perform thorough quality assurance testing to ensure a stable release. Our revised delivery date would be next Wednesday. I appreciate your understanding and support.

Best regards,
[Your Name]', 
    'Step-by-step Solution Breakdown:

Step 1: Subject Line
- Must be clear, professional, and state the exact purpose (e.g. ''Request for Project Deadline Extension'').

Step 2: Salutation
- Use a formal salutation (e.g. ''Dear [Manager''s Name],'').

Step 3: Opening Statement
- State the request clearly in the first sentence (requesting a 3-day extension from Friday).

Step 4: Body Paragraph (The Delay Reasons)
- List the technical challenges professionally (API integration difficulties, server downtime).

Step 5: Proposed Timeline & Value Addition
- Propose the new timeline (next Wednesday) and explain why the extension is beneficial (allows for thorough QA testing for a stable release).

Step 6: Closing & Sign-off
- Professional closing expression (''I appreciate your understanding'') followed by sign-off (''Best regards, [Your Name]'').', NULL, 'Email Writing', 'Professional Communication', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 540, 
    'Writing less than 100 words, using informal slang, or failing to state the exact reasons and new date.', ARRAY['email-writing', 'writing-skills', 'business-english']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #43 (Verbal Ability - Synonyms and Antonyms)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0043', 'Choose the word which is closest in meaning to the bold word in the sentence:
The speaker''s **eloquent** presentation captivated the entire audience.', NULL, '[{"id": "A", "text": "boring"}, {"id": "B", "text": "persuasive and expressive"}, {"id": "C", "text": "loud"}, {"id": "D", "text": "confusing"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Understand the sentence context.
The speaker''s presentation ''captivated the entire audience''. This indicates that the presentation was highly effective, fluent, and pleasing to listen to.

Step 2: Define the word ''eloquent''.
''Eloquent'' means fluent, persuasive, and powerful in speaking or writing.

Step 3: Evaluate the options.
- ''boring'': Antonym of what would captivate an audience. Incorrect.
- ''persuasive and expressive'': Directly aligns with the definition of eloquent. Correct.
- ''loud'': While a speaker might be loud, loudness alone is not equivalent to eloquence. Incorrect.
- ''confusing'': Would not captivate an audience positively. Incorrect.

Therefore, ''persuasive and expressive'' is the correct choice.', NULL, 'Synonyms and Antonyms', 'Synonyms', 
    'Easy'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 20, 
    'Choosing ''loud'' because of the association with public speaking, or selecting antonyms like ''boring''.', ARRAY['vocabulary', 'synonyms']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #44 (Verbal Ability - Synonyms and Antonyms)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0044', 'Choose the word which is opposite in meaning to the bold word in the sentence:
Her decision to resign was **evanescent**, as she changed her mind the very next day.', NULL, '[{"id": "A", "text": "permanent"}, {"id": "B", "text": "temporary"}, {"id": "C", "text": "foolish"}, {"id": "D", "text": "spontaneous"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Analyze the sentence context.
''She changed her mind the very next day'' indicates that her decision lasted only a very short time.

Step 2: Define ''evanescent''.
''Evanescent'' means quickly fading, vanishing, or lasting for a very short time (temporary).

Step 3: Identify the goal.
We need to find the word *opposite* in meaning (antonym).

Step 4: Evaluate the options.
- ''permanent'': Lasting or intended to last indefinitely. This is the direct opposite of temporary/evanescent. Correct.
- ''temporary'': Synonym of evanescent. Incorrect.
- ''foolish'': Unrelated. Incorrect.
- ''spontaneous'': Performed or occurring as a result of a sudden impulse. Unrelated. Incorrect.

Therefore, the opposite in meaning is ''permanent''.', NULL, 'Synonyms and Antonyms', 'Antonyms', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 30, 
    'Selecting ''temporary'' (which is the synonym) instead of the antonym ''permanent''.', ARRAY['vocabulary', 'antonyms']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

-- Question #45 (Verbal Ability - Sentence Completion)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0045', 'Fill in the blank with the correct set of words:
If we ______ the project on time, we ______ the contract for next year.', NULL, '[{"id": "A", "text": "complete, secure"}, {"id": "B", "text": "will complete, will secure"}, {"id": "C", "text": "complete, will secure"}, {"id": "D", "text": "completed, will secure"}]'::jsonb, 'C', 
    'Step-by-step Solution:

Step 1: Identify the type of conditional sentence.
This sentence describes a possible future condition and its probable result. This represents a First Conditional structure.

Step 2: Recall the grammatical rules for First Conditionals.
- The condition clause (''if'' clause) takes the Simple Present tense.
- The result clause takes the Future tense (will + base verb).

Step 3: Apply the rule to the clauses.
- If clause: ''If we [simple present] the project...'' -> ''complete''
- Result clause: ''...we [will + base verb] the contract...'' -> ''will secure''

Step 4: Match with options.
This selection (''complete'', ''will secure'') corresponds to Option C.

Therefore, option C is correct.', NULL, 'Sentence Completion', 'Conditional Sentences', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 30, 
    'Using ''will'' in both clauses (''will complete, will secure''), which violates English conditional grammar rules.', ARRAY['conditionals', 'grammar', 'verb-tenses']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #46 (Verbal Ability - Reading Comprehension)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0046', 'Read the passage and answer the question:
"Although biofuels are cleaner than traditional fossil fuels, their production requires massive amounts of agricultural land. Critics argue that diverting food crops like corn for fuel production pushes global food prices up, disproportionately affecting low-income nations."
Which of the following is the most logical inference from the passage?', NULL, '[{"id": "A", "text": "Biofuels are not actually cleaner than fossil fuels."}, {"id": "B", "text": "Biofuel production can have negative economic impacts on poor countries."}, {"id": "C", "text": "Fossil fuels are cheaper to produce than biofuels."}, {"id": "D", "text": "Low-income nations should not use biofuels."}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Analyze the statements in the passage.
- Fact 1: Biofuels are cleaner than traditional fossil fuels.
- Fact 2: Biofuel production requires significant agricultural land.
- Fact 3: Diverting crops for fuel increases global food prices.
- Fact 4: Raising food prices disproportionately affects low-income nations.

Step 2: Evaluate the option inferences.
- Option A: Contradicts Fact 1. Incorrect.
- Option B: Combining Fact 3 and Fact 4 (raising food prices disproportionately affects low-income nations) logically implies that biofuel production can cause negative economic harm/impacts on poor countries. This is a direct, valid inference. Correct.
- Option C: The passage does not compare the production costs of fossil fuels versus biofuels. Incorrect.
- Option D: The passage describes consequences but does not offer recommendations or policy prescriptions on whether they should use it. Incorrect.

Therefore, Option B is the most logical inference.', NULL, 'Reading Comprehension', 'Logical Inference', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 70, 
    'Choosing A (which directly contradicts the statement ''biofuels are cleaner'') or D (which is a recommendation, not a logical inference based strictly on the text).', ARRAY['reading-comprehension', 'inference', 'verbal-reasoning']::text[], 'Inspired'::nqt_source_type, 2024, 4, TRUE
);

-- Question #47 (Verbal Ability - Idioms and Phrases)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0047', 'Select the correct meaning of the bold idiom in the sentence:
The detective had to **leave no stone unturned** to solve the complicated mystery case.', NULL, '[{"id": "A", "text": "destroy all evidence"}, {"id": "B", "text": "try every possible course of action"}, {"id": "C", "text": "give up searching"}, {"id": "D", "text": "accuse innocent people"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Identify the bold idiom.
The idiom is ''leave no stone unturned''.

Step 2: Recall the definition of the idiom.
''Leave no stone unturned'' originates from Greek drama/mythology and means to use every possible source, try every option, or exhaust all courses of action in search of a goal.

Step 3: Evaluate the options.
- ''destroy all evidence'': Opposite of solving a case. Incorrect.
- ''try every possible course of action'': Directly aligns with the idiom definition. Correct.
- ''give up searching'': Opposite meaning. Incorrect.
- ''accuse innocent people'': Unrelated. Incorrect.

Therefore, option B is correct.', NULL, 'Idioms and Phrases', 'Idiom Meanings', 
    'Easy'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 20, 
    'Interpreting the phrase literally (moving stones) or choosing a negative action like A.', ARRAY['idioms', 'vocabulary']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #48 (Verbal Ability - Sentence Improvement)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0048', 'Improve the underlined part of the sentence:
If I **was you**, I would have accepted the job offer immediately.', NULL, '[{"id": "A", "text": "was like you"}, {"id": "B", "text": "were you"}, {"id": "C", "text": "am you"}, {"id": "D", "text": "No improvement needed"}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Analyze the sentence structure and meaning.
The sentence ''If I was you, I would have...'' represents an imaginary, counterfactual, or hypothetical condition (I cannot literally be you).

Step 2: Recall the grammar rule for hypothetical/subjunctive statements.
In formal English, imaginary or counterfactual conditional clauses require the subjunctive mood. The subjunctive past of ''to be'' is always ''were'' for all subjects (I, you, he, she, it, they).

Step 3: Formulate the correction.
''was you'' must be corrected to ''were you'' to satisfy the subjunctive requirement.

Step 4: Match with options.
This corresponds to Option B.

Therefore, option B is correct.', NULL, 'Sentence Improvement', 'Subjunctive Mood', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 35, 
    'Thinking ''was'' is correct because ''I'' is singular, forgetting that imaginary conditionals require ''were''.', ARRAY['subjunctive', 'grammar', 'sentence-improvement']::text[], 'Inspired'::nqt_source_type, 2024, 4, TRUE
);

-- Question #49 (Verbal Ability - Active and Passive Voice)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0049', 'Choose the option that represents the correct active voice of the sentence:
The road is being repaired by the municipal corporation.', NULL, '[{"id": "A", "text": "The municipal corporation repaired the road."}, {"id": "B", "text": "The municipal corporation is repairing the road."}, {"id": "C", "text": "The municipal corporation was repairing the road."}, {"id": "D", "text": "The municipal corporation repairs the road."}]'::jsonb, 'B', 
    'Step-by-step Solution:

Step 1: Identify the subject, object, and verb in the passive sentence.
- Passive Subject (receiver): ''The road''
- Passive Agent (doer): ''the municipal corporation''
- Passive Verb: ''is being repaired'' (Present Continuous Passive)

Step 2: Recall voice conversion rules for Present Continuous.
- Passive structure: Subject + is/am/are + being + past participle (V3) + by + Agent
- Active structure: Agent + is/am/are + present participle (V1-ing) + Subject

Step 3: Convert the sentence.
- Active Subject (Agent): ''The municipal corporation''
- Active Verb: ''is repairing'' (agrees with singular corporation)
- Active Object (Subject): ''the road''
Combined: ''The municipal corporation is repairing the road.''

Step 4: Match with options.
This matches Option B.

Therefore, option B is correct.', NULL, 'Active and Passive Voice', 'Voice Conversion', 
    'Easy'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 30, 
    'Changing the tense of the sentence (e.g., choosing A which is simple past, or C which is past continuous).', ARRAY['voice', 'grammar', 'active-voice']::text[], 'Original'::nqt_source_type, 2024, 5, TRUE
);

-- Question #50 (Verbal Ability - Direct and Indirect Speech)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0050', 'Convert the following direct speech to indirect speech:
He said to me, "Where are you going?"', NULL, '[{"id": "A", "text": "He asked me where I was going."}, {"id": "B", "text": "He told me where I was going."}, {"id": "C", "text": "He asked me where was I going."}, {"id": "D", "text": "He asked me that where was I going."}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Convert the reporting verb.
Since the direct speech is a question, ''said to me'' changes to ''asked me''.

Step 2: Convert the connecting word.
For WH-questions (where, what, why, etc.), the question word itself acts as the connector. Do NOT use the conjunction ''that''.

Step 3: Convert the question clause structure.
The question ''Where are you going?'' (interrogative structure: Verb + Subject) must change into an assertive structure (Subject + Verb) in indirect speech:
- Direct: ''where are [verb] you [subject] going?''
- Indirect: ''where I [subject] was [verb] going''

Step 4: Shift pronouns and tenses.
- Pronoun: ''you'' changes to ''I'' (agrees with the object of reporting verb, ''me'').
- Tense: Present Continuous (''are going'') shifts to Past Continuous (''was going'').

Combining the steps: ''He asked me where I was going.''
This matches Option A.

Therefore, option A is correct.', NULL, 'Direct and Indirect Speech', 'Speech Conversion', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'MCQ'::nqt_question_type, 40, 
    'Retaining the question word order (''where was I going'' instead of ''where I was going'') or incorrectly adding ''that'' (Option D).', ARRAY['speech', 'indirect-speech', 'grammar']::text[], 'Inspired'::nqt_source_type, 2023, 4, TRUE
);

