-- Question #52 (Numerical Ability - Time and Work)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0052', 'Developer A can build an API module in 11 days, and Developer B can build it in 17 days. If they work on alternate days starting with A, in how many days will the API be completed?', NULL, '[{"id": "A", "text": "13.18 days"}, {"id": "B", "text": "12.48 days"}, {"id": "C", "text": "13.68 days"}, {"id": "D", "text": "14.23 days"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Calculate individual day rates: A = 1/11, B = 1/17.
Step 2: Alternate day-by-day accumulation gives exactly 13.18 days.', NULL, 'Time and Work', 'Alternate Days', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['time-and-work', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

-- Question #53 (Reasoning Ability - Coding Decoding)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0053', 'In a certain code language, if ''SPRING'' is encrypted as ''XUWNSL'', how will ''SEEDS'' be written in that same cipher system?', NULL, '[{"id": "A", "text": "XJJIX"}, {"id": "B", "text": "YKKJY"}, {"id": "C", "text": "WIIHW"}, {"id": "D", "text": "ZLLKZ"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Compare SPRING -> XUWNSL. Each letter is shifted forward by 5.
Step 2: Apply the same +5 shift to ''SEEDS'' to get ''XJJIX''.', NULL, 'Coding Decoding', 'Pattern Shifts', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 65, 
    'Misidentifying relationship paths.', ARRAY['coding-decoding', 'reasoning-aptitude']::text[], 'Inspired'::nqt_source_type, 2023, 2, TRUE
);

-- Question #54 (Advanced Quantitative and Reasoning Ability - Equations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0054', 'The sum of the squares of two consecutive positive odd integers is 650. What is the sum of these two integers?', NULL, '[{"id": "A", "text": "36"}, {"id": "B", "text": "34"}, {"id": "C", "text": "40"}, {"id": "D", "text": "32"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Let numbers be x and x+2. x^2 + (x+2)^2 = 650.
Step 2: 2x^2 + 4x + 4 = 650 => x^2 + 2x - 323 = 0.
Step 3: Solving gives x=17. The integers are 17 and 19. Sum = 36.', NULL, 'Equations', 'Quadratic Roots', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['equations', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

