) VALUES (
    'NQT-0055', 'Passage Recall:
Microservices decompose a software application into small, independently deployable services that communicate via lightweight APIs. This decentralized approach allows development teams to work autonomously and scale parts of the system independently. However, managing distributed data transactions and tracking performance logs across multiple nodes increases operational complexity.', NULL, NULL, 'Microservices break systems into small autonomous components connected via APIs. This supports modular scaling and updates. However, it increases the overhead for distributed transactions and troubleshooting logs.', 
    'Provide a brief summary containing the core definitions and quantitative figures mentioned in the text.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out vital numerical statistics or terms.', ARRAY['passage-recall', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

-- Question #56 (Numerical Ability - Profit and Loss)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0056', 'A grain dealer claims to sell wheat at his cost price but uses a deceptive balance that measures 750 grams instead of 1 kg. What is his net gain percentage?', NULL, '[{"id": "A", "text": "33.33%"}, {"id": "B", "text": "25.0%"}, {"id": "C", "text": "25.0%"}, {"id": "D", "text": "31.53%"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Profit is earned on the actual weight delivered.
Profit % = (Cheated weight / Sold weight) * 100 = (250 / 750) * 100 = 33.33%.', NULL, 'Profit and Loss', 'Dishonest Dealer', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['profit-and-loss', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

