INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0057', 'In a certain code language, if ''CANOPY'' is encrypted as ''ECPQRA'', how will ''PLANT'' be written in that same cipher system?', NULL, '[{"id": "A", "text": "RNCPV"}, {"id": "B", "text": "SODQW"}, {"id": "C", "text": "QMBOU"}, {"id": "D", "text": "TPERX"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Compare CANOPY -> ECPQRA. Each letter is shifted forward by 2.
Step 2: Apply the same +2 shift to ''PLANT'' to get ''RNCPV''.', NULL, 'Coding Decoding', 'Pattern Shifts', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 65, 
