) VALUES (
    'NQT-0079', 'Passage Recall:
Photosynthesis converts light energy into chemical energy inside chloroplasts. Chlorophyll pigments absorb sunlight to split water, releasing oxygen. Carbon dioxide is captured to synthesize glucose. The process comprises light-dependent steps yielding ATP/NADPH, and the Calvin Cycle which fixes carbon into sugars.', NULL, NULL, 'Photosynthesis captures light energy in plant chloroplasts using chlorophyll. Water molecules are split to emit oxygen, and carbon dioxide is processed during the Calvin Cycle to form glucose sugars.', 
    'Provide a brief summary containing the core definitions and quantitative figures mentioned in the text.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out vital numerical statistics or terms.', ARRAY['passage-recall', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

-- Question #80 (Numerical Ability - Percentages)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0080', 'The population of a technology park increased by 10% in the first year and decreased by 8% in the second year. If the current population is 26312, what was the population two years ago?', NULL, '[{"id": "A", "text": "26000"}, {"id": "B", "text": "25600"}, {"id": "C", "text": "26800"}, {"id": "D", "text": "24700"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Formula: Final = Initial * (1 + p1/100) * (1 - p2/100).
Here, p1=10%, p2=8%, and Final=26312.

Step 2: Solve for Initial.
Initial = 26312 / ((1 + 10/100) * (1 - 8/100)) = 26000.', NULL, 'Percentages', 'Successive Changes', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['percentages', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

