) VALUES (
    'NQT-0082', 'An infinite geometric progression has an overall sum of 10. If the first term is 12, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "-0.2"}, {"id": "B", "text": "-0.28"}, {"id": "C", "text": "-0.08"}, {"id": "D", "text": "1.2"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Sum S = a / (1 - r) => 10 = 12 / (1 - r).
Step 2: 1 - r = 12/10 => r = 1 - 12/10 = -0.2.', NULL, 'Progressions', 'Geometric Progressions', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['progressions', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

