    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0091', 'Passage Recall:
Quantum computing utilizes qubits instead of classical bits. While bits represent 0 or 1, qubits exist in superpositions of both states, allowing parallel computations. Quantum entanglement links qubits instantaneously across distances. These properties enable quantum computers to solve cryptographic and optimization problems exponentially faster than classical systems. However, maintaining qubit stability (coherence) requires sub-zero temperatures, presenting a major hardware challenge.', NULL, NULL, 'Quantum computing leverages superposition and entanglement of qubits to perform complex calculations exponentially faster than classical bits. Qubits represent both 0 and 1 simultaneously. A key bottleneck in development is coherence, which requires extreme sub-zero cooling.', 
    'Provide a brief summary containing the core definitions and quantitative figures mentioned in the text.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out vital numerical statistics or terms.', ARRAY['passage-recall', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

