    'NQT-0106', 'An infinite geometric progression has an overall sum of 22. If the first term is 4, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "0.818"}, {"id": "B", "text": "0.738"}, {"id": "C", "text": "0.938"}, {"id": "D", "text": "0.182"}]'::jsonb, 'A', 
