) VALUES (
    'NQT-0126', 'The sum of the squares of two consecutive positive odd integers is 130. What is the sum of these two integers?', NULL, '[{"id": "A", "text": "16"}, {"id": "B", "text": "14"}, {"id": "C", "text": "20"}, {"id": "D", "text": "12"}]'::jsonb, 'A', 
    'Step-by-step Solution:

