) VALUES (
    'NQT-0130', 'An infinite geometric progression has an overall sum of 16. If the first term is 10, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "0.375"}, {"id": "B", "text": "0.295"}, {"id": "C", "text": "0.495"}, {"id": "D", "text": "0.625"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Sum S = a / (1 - r) => 16 = 10 / (1 - r).
Step 2: 1 - r = 10/16 => r = 1 - 10/16 = 0.375.', NULL, 'Progressions', 'Geometric Progressions', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['progressions', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

