    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0140', 'The population of a technology park increased by 10% in the first year and decreased by 8% in the second year. If the current population is 30866, what was the population two years ago?', NULL, '[{"id": "A", "text": "30500"}, {"id": "B", "text": "30100"}, {"id": "C", "text": "31300"}, {"id": "D", "text": "28975"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Formula: Final = Initial * (1 + p1/100) * (1 - p2/100).
Here, p1=10%, p2=8%, and Final=30866.

Step 2: Solve for Initial.
Initial = 30866 / ((1 + 10/100) * (1 - 8/100)) = 30500.', NULL, 'Percentages', 'Successive Changes', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['percentages', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
