    'NQT-0144', 'A pipe can fill a storage tank in 5 hours. However, due to a leakage at the base, it takes 7 hours to fill. How long will the leak take to empty a completely full tank?', NULL, '[{"id": "A", "text": "17.5 hours"}, {"id": "B", "text": "18.7 hours"}, {"id": "C", "text": "16.7 hours"}, {"id": "D", "text": "20.12 hours"}]'::jsonb, 'A', 
