-- Question #150 (Advanced Quantitative and Reasoning Ability - Equations)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0150', 'The sum of the squares of two consecutive positive odd integers is 394. What is the sum of these two integers?', NULL, '[{"id": "A", "text": "28"}, {"id": "B", "text": "26"}, {"id": "C", "text": "32"}, {"id": "D", "text": "24"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Let numbers be x and x+2. x^2 + (x+2)^2 = 394.
Step 2: 2x^2 + 4x + 4 = 394 => x^2 + 2x - 195 = 0.
Step 3: Solving gives x=13. The integers are 13 and 15. Sum = 28.', NULL, 'Equations', 'Quadratic Roots', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['equations', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

