    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['pipes-and-cisterns', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
