    'NQT-0168', 'The difference between simple interest and compound interest (compounded annually) on a deposit for 2 years at 3% per annum is Rs. 39. Find the total deposit amount.', NULL, '[{"id": "A", "text": "Rs. 43333"}, {"id": "B", "text": "Rs. 43183"}, {"id": "C", "text": "Rs. 43633"}, {"id": "D", "text": "Rs. 44199"}]'::jsonb, 'A', 
    'Step-by-step Solution:

