    'NQT-0186', 'The sum of the squares of two consecutive positive odd integers is 514. What is the sum of these two integers?', NULL, '[{"id": "A", "text": "32"}, {"id": "B", "text": "30"}, {"id": "C", "text": "36"}, {"id": "D", "text": "28"}]'::jsonb, 'A', 
