    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0214', 'An infinite geometric progression has an overall sum of 22. If the first term is 10, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "0.545"}, {"id": "B", "text": "0.465"}, {"id": "C", "text": "0.665"}, {"id": "D", "text": "0.455"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Sum S = a / (1 - r) => 22 = 10 / (1 - r).
Step 2: 1 - r = 10/22 => r = 1 - 10/22 = 0.545.', NULL, 'Progressions', 'Geometric Progressions', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['progressions', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

