    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0215', 'Email Writing - Situation Prompt:
Write a professional email to the support manager requesting scheduling an extra onboarding training session for our incoming cohort of five junior software engineers. Use a professional tone, construct full sentences, and keep the word count between 100-150 words.', NULL, NULL, 'Subject: Request Regarding Scheduling An Extra Onboarding Training Session

Dear Support Manager,

I hope you are doing well.

I am writing to formally request scheduling an extra onboarding training session for our incoming cohort of five junior software engineers. This adjustment will ensure that our team has sufficient capacity to deliver high-quality results without compromising the project standards.

We appreciate your guidance and look forward to your approval of this request.

Best regards,
[Your Name]', 
    'Evaluate based on formal subject line, introduction stating request for scheduling an extra onboarding training session, professional tone, and length.', NULL, 'Email Writing', 'Professional Communication', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 540, 
    'Exceeding the word limit or using informal vocabulary.', ARRAY['email-writing', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

