    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0220', 'The population of a technology park increased by 10% in the first year and decreased by 6% in the second year. If the current population is 37741, what was the population two years ago?', NULL, '[{"id": "A", "text": "36500"}, {"id": "B", "text": "36100"}, {"id": "C", "text": "37300"}, {"id": "D", "text": "34675"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Formula: Final = Initial * (1 + p1/100) * (1 - p2/100).
Here, p1=10%, p2=6%, and Final=37741.

Step 2: Solve for Initial.
Initial = 37741 / ((1 + 10/100) * (1 - 6/100)) = 36500.', NULL, 'Percentages', 'Successive Changes', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['percentages', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

