    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0227', 'Email Writing - Situation Prompt:
Write a professional email to the HR director requesting the postponement of the system integration test because of unresolved bugs in the payment gateway code. Use a professional tone, construct full sentences, and keep the word count between 100-150 words.', NULL, NULL, 'Subject: Request Regarding The Postponement Of The System Integration Test

Dear Hr Director,

I hope you are doing well.

I am writing to formally request the postponement of the system integration test because of unresolved bugs in the payment gateway code. This adjustment will ensure that our team has sufficient capacity to deliver high-quality results without compromising the project standards.

We appreciate your guidance and look forward to your approval of this request.

Best regards,
[Your Name]', 
    'Evaluate based on formal subject line, introduction stating request for the postponement of the system integration test, professional tone, and length.', NULL, 'Email Writing', 'Professional Communication', 
    'Medium'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 540, 
    'Exceeding the word limit or using informal vocabulary.', ARRAY['email-writing', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

-- Question #228 (Numerical Ability - Simple and Compound Interest)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0228', 'The difference between simple interest and compound interest (compounded annually) on a deposit for 2 years at 3% per annum is Rs. 39. Find the total deposit amount.', NULL, '[{"id": "A", "text": "Rs. 43333"}, {"id": "B", "text": "Rs. 43183"}, {"id": "C", "text": "Rs. 43633"}, {"id": "D", "text": "Rs. 44199"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Use difference formula: D = P * (R/100)^2.
Here, 39 = P * (3/100)^2.
Step 2: Solve for P = 43333.', NULL, 'Simple and Compound Interest', 'Difference between SI and CI', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['simple-and-compound-interest', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

-- Question #229 (Reasoning Ability - Coding Decoding)
INSERT INTO nqt_questions (
