    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0229', 'In a certain code language, if ''FLOWER'' is encrypted as ''LRUCKX'', how will ''ROOTS'' be written in that same cipher system?', NULL, '[{"id": "A", "text": "XUUZY"}, {"id": "B", "text": "YVVAZ"}, {"id": "C", "text": "WTTYX"}, {"id": "D", "text": "ZWWBA"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Compare FLOWER -> LRUCKX. Each letter is shifted forward by 6.
Step 2: Apply the same +6 shift to ''ROOTS'' to get ''XUUZY''.', NULL, 'Coding Decoding', 'Pattern Shifts', 
    'Easy'::nqt_difficulty, 'Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 65, 
    'Misidentifying relationship paths.', ARRAY['coding-decoding', 'reasoning-aptitude']::text[], 'Inspired'::nqt_source_type, 2023, 2, TRUE
);

