) VALUES (
    'NQT-0230', 'If log_2(x) + log_4(x) + log_16(x) = 21, find the value of x.', NULL, '[{"id": "A", "text": "4096"}, {"id": "B", "text": "4092"}, {"id": "C", "text": "4128"}, {"id": "D", "text": "8192"}]'::jsonb, 'A', 
