    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0235', 'Passage Recall:
Deep learning uses multi-layered artificial neural networks to learn representations from raw data. Convolutional Neural Networks (CNNs) excel at spatial image analysis, while Recurrent Neural Networks (RNNs) process sequential text and audio. Training deep models requires massive labeled datasets and high-performance GPUs. Overfitting occurs when models memorize training noise rather than general patterns.', NULL, NULL, 'Deep learning employs neural networks with multiple hidden layers. CNNs analyze visual inputs, while RNNs handle sequence data. Training requires substantial data and GPU compute, with overfitting remaining a primary risk.', 
    'Provide a brief summary containing the core definitions and quantitative figures mentioned in the text.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out vital numerical statistics or terms.', ARRAY['passage-recall', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

