) VALUES (
    'NQT-0236', 'A grain dealer claims to sell wheat at his cost price but uses a deceptive balance that measures 875 grams instead of 1 kg. What is his net gain percentage?', NULL, '[{"id": "A", "text": "14.29%"}, {"id": "B", "text": "12.5%"}, {"id": "C", "text": "12.5%"}, {"id": "D", "text": "12.49%"}]'::jsonb, 'A', 
    'Step-by-step Solution:

