    'NQT-0248', 'The difference between simple interest and compound interest (compounded annually) on a deposit for 2 years at 7% per annum is Rs. 39. Find the total deposit amount.', NULL, '[{"id": "A", "text": "Rs. 7959"}, {"id": "B", "text": "Rs. 7809"}, {"id": "C", "text": "Rs. 8259"}, {"id": "D", "text": "Rs. 8118"}]'::jsonb, 'A', 
