) VALUES (
    'NQT-0250', 'An infinite geometric progression has an overall sum of 22. If the first term is 12, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "0.455"}, {"id": "B", "text": "0.375"}, {"id": "C", "text": "0.575"}, {"id": "D", "text": "0.545"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Sum S = a / (1 - r) => 22 = 12 / (1 - r).
