    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0258', 'The sum of the squares of two consecutive positive odd integers is 802. What is the sum of these two integers?', NULL, '[{"id": "A", "text": "40"}, {"id": "B", "text": "38"}, {"id": "C", "text": "44"}, {"id": "D", "text": "36"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Let numbers be x and x+2. x^2 + (x+2)^2 = 802.
Step 2: 2x^2 + 4x + 4 = 802 => x^2 + 2x - 399 = 0.
Step 3: Solving gives x=19. The integers are 19 and 21. Sum = 40.', NULL, 'Equations', 'Quadratic Roots', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['equations', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

-- Question #259 (Verbal Ability - Passage Recall)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0259', 'Passage Recall:
Quantum computing utilizes qubits instead of classical bits. While bits represent 0 or 1, qubits exist in superpositions of both states, allowing parallel computations. Quantum entanglement links qubits instantaneously across distances. These properties enable quantum computers to solve cryptographic and optimization problems exponentially faster than classical systems. However, maintaining qubit stability (coherence) requires sub-zero temperatures, presenting a major hardware challenge.', NULL, NULL, 'Quantum computing leverages superposition and entanglement of qubits to perform complex calculations exponentially faster than classical bits. Qubits represent both 0 and 1 simultaneously. A key bottleneck in development is coherence, which requires extreme sub-zero cooling.', 
    'Provide a brief summary containing the core definitions and quantitative figures mentioned in the text.', NULL, 'Passage Recall', 'Written Reconstruction', 
    'Hard'::nqt_difficulty, 'Verbal Ability'::nqt_section, 'Text'::nqt_question_type, 120, 
    'Leaving out vital numerical statistics or terms.', ARRAY['passage-recall', 'verbal-ability', 'writing']::text[], 'Original'::nqt_source_type, 2024, 3, TRUE
);

-- Question #260 (Numerical Ability - Percentages)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0260', 'The population of a technology park increased by 10% in the first year and decreased by 8% in the second year. If the current population is 39974, what was the population two years ago?', NULL, '[{"id": "A", "text": "39500"}, {"id": "B", "text": "39100"}, {"id": "C", "text": "40300"}, {"id": "D", "text": "37525"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Formula: Final = Initial * (1 + p1/100) * (1 - p2/100).
Here, p1=10%, p2=8%, and Final=39974.

Step 2: Solve for Initial.
Initial = 39974 / ((1 + 10/100) * (1 - 8/100)) = 39500.', NULL, 'Percentages', 'Successive Changes', 
    'Medium'::nqt_difficulty, 'Numerical Ability'::nqt_section, 'MCQ'::nqt_question_type, 75, 
    'Computational errors in fractions.', ARRAY['percentages', 'numerical-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 2, TRUE
);

