-- Question #298 (Advanced Quantitative and Reasoning Ability - Progressions)
INSERT INTO nqt_questions (
    code, question_text, question_image_url, options, correct_answer, 
    explanation, explanation_image_url, topic, subtopic, 
    difficulty, section, question_type, estimated_solve_time, 
    common_mistakes, tags, source, exam_year, frequency, verified
) VALUES (
    'NQT-0298', 'An infinite geometric progression has an overall sum of 10. If the first term is 10, find the common ratio of the progression.', NULL, '[{"id": "A", "text": "0.0"}, {"id": "B", "text": "-0.08"}, {"id": "C", "text": "0.12"}, {"id": "D", "text": "1.0"}]'::jsonb, 'A', 
    'Step-by-step Solution:

Step 1: Sum S = a / (1 - r) => 10 = 10 / (1 - r).
Step 2: 1 - r = 10/10 => r = 1 - 10/10 = 0.0.', NULL, 'Progressions', 'Geometric Progressions', 
    'Hard'::nqt_difficulty, 'Advanced Quantitative and Reasoning Ability'::nqt_section, 'MCQ'::nqt_question_type, 110, 
    'Forgetting the base conversions in logarithms.', ARRAY['progressions', 'advanced-aptitude']::text[], 'Inspired'::nqt_source_type, 2024, 3, TRUE
);

