) VALUES (
    'NQT-0299', 'Email Writing - Situation Prompt:
Write a professional email to the HR director requesting the postponement of the system integration test because of unresolved bugs in the payment gateway code. Use a professional tone, construct full sentences, and keep the word count between 100-150 words.', NULL, NULL, 'Subject: Request Regarding The Postponement Of The System Integration Test

Dear Hr Director,

